import requests
from bs4 import BeautifulSoup
from urllib.parse import urljoin

# Define the base URL
base_url = 'https://docs.databricks.com/en/release-notes/product/'

# List of months and years
months = ['january', 'february', 'march', 'april', 'may', 'june', 'july', 'august', 'september', 'october', 'november', 'december']
years = ['2023', '2024']

results = []
# Initialize a list to store extracted data

# Iterate through each year and month
for year in years:
    for month in months:
        url = f'{base_url}{year}/{month}.html'
        response = requests.get(url)
        if response.status_code == 200:
            # Get the content of the response
            page_content = response.content
            # Step 1: Send an HTTP request to the webpage

            # Step 2: Parse the HTML content using BeautifulSoup
            soup = BeautifulSoup(response.content, 'html.parser')

            # Step 3: Extract all the <div> sections in the article body
            sections = soup.find_all('div', class_='section')

            # Step 4: Loop through each section to extract the required elements
            for i, section in enumerate(sections):
                if i == 0:
                    continue  # Skip the first section

                h2 = section.find('h2')  # Extract the title
                p_tags = section.find_all('p')  # Extract all <p> tags

                if h2 and len(p_tags) > 1:
                    title = h2.get_text(strip=True)
                    info = p_tags[1].get_text(strip=True)  # Extract the second <p> tag's text

                    # Remove text after "See"
                    info = info.split('See')[0].strip()

                    # Extract text from <ul> elements with class 'simple'
                    ul_simple = section.find('ul', class_='simple')
                    if ul_simple:
                        ul_text = ' '.join(li.get_text(strip=True) for li in ul_simple.find_all('li'))
                        info += f" {ul_text}"

                    # Extract links in the "See" section (if present)
                    see_links = section.find_all('a')
                    links = []

                    if see_links:
                        for link in see_links:
                            href = link.get('href')
                            if href and '#' not in href:  # Filter out links with '#'
                                absolute_href = urljoin(url, href)  # Convert to absolute URL
                                link_text = link.get_text(strip=True)
                                links.append(f"{absolute_href}")

                    # Append the title, information, links, and month to the results list
                    results.append([title, info, links, month, year])

# Print the results
for result in results:
    print(f"Title: {result[0]}")
    print(f"Information: {result[1]}")
    for link in result[2]:
        print(link)
    print(f"Month: {result[3]}")
    print(f"Year: {result[4]}")
    print("\n" + "="*50 + "\n")

# COMMAND ----------

display(results)

