from pyspark.sql.types import StructType, StringType, ArrayType

# Define the schema
schema = StructType() \
    .add("title", StringType()) \
    .add("description", StringType()) \
    .add("links", ArrayType(StringType())) \
    .add("month", StringType()) \
    .add("year", StringType())

# Create the DataFrame with the specified schema
df = spark.createDataFrame(results, schema)

# Display the DataFrame
display(df)

# Write the DataFrame as a Delta table
df.write.format("delta").mode("overwrite").option('mergeSchema', 'true').saveAsTable("datas")

